import React, { useEffect, useState } from 'react';
import vacancies from '../../constants/vacancies';
import { useLocation } from 'react-router-dom';
import useMobile from '../../helpers/hooks/useMobile';
import useTablet from '../../helpers/hooks/useTablet';
import { useInView } from 'react-intersection-observer';
import * as Styled from './styles';
import { DarkSubTitle } from '../../styles/common';
import {ReactComponent as Person} from '../../assets/images/Person.svg';
import {ReactComponent as Build} from '../../assets/images/Build.svg';
import Button from '../../components/Button';
import VacancyList from '../../components/VacancyList';
import CEOSection from '../_sections/CEOSection';
import CareerContactSection from '../_sections/CareerContactSection';
import setLoaderStatus from '../../helpers/functions/setLoaderStatus';

const Vacancy = () => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
	const isMobile = useMobile();
    const isTablet = useTablet();
    const location = useLocation();
    const pageId = location.pathname.substring(location.pathname.lastIndexOf('/') + 1);
    const currentVacancy = vacancies.find(vacancy => vacancy.id === pageId);
    const [isSplineloaded, setIsSplineLoaded] = useState(false);
    
    useEffect(()=> {
        window.scrollTo(0, 0);
        setLoaderStatus(isSplineloaded);
        
        return setLoaderStatus(false);
    },[isSplineloaded])

    return (
        <Styled.VacancySectionContainer>
            <Styled.VacancySection isMobile={isMobile} isTablet={isTablet}>
                <Styled.Header ref={ref} inView={inView} >
                    <DarkSubTitle>{currentVacancy.title}</DarkSubTitle>
                    <Styled.MetaDataContainer>
                        <Styled.Degree><Person/> {currentVacancy.degree}</Styled.Degree>
                        <Styled.WorkType><Build/> {currentVacancy.workType}</Styled.WorkType>
                    </Styled.MetaDataContainer>
                    <Styled.Description>{currentVacancy.description}</Styled.Description>
                    <Button>Apply</Button>
                </Styled.Header>
                <Styled.ListsContainer>
                    <VacancyList 
                        title={'Responsibilities'}
                        list={currentVacancy.responsibilities}
                    />
                    <VacancyList 
                        title={'Requirements'}
                        list={currentVacancy.responsibilities}
                    />
                    <VacancyList 
                        title={'We propose'}
                        list={currentVacancy.wePropose}
                    />
                </Styled.ListsContainer>
            </Styled.VacancySection>
            <CEOSection 
                title='Join our team in a flash'
                subtitle='Drop Jito your CV, and we will contact you shortly. We don’t have an  endless process of interviews, so don’t hesitate to apply!'
            />
            <CareerContactSection setIsSplineLoaded={setIsSplineLoaded}/>
        </Styled.VacancySectionContainer>
    );
};

export default Vacancy;